Here's a high-level example of how you can implement this in Python:

```python
import os
import pickle
from collections import OrderedDict

class IndexCache:
    def __init__(self, index_file_path):
        self.index_file_path = index_file_path
        self.cache = OrderedDict()

    def get(self, key):
        if key in self.cache:
            value, timestamp = self.cache[key]
            if timestamp < os.stat(self.index_file_path).st_mtime:
                # Cache has expired, remove it
                del self.cache[key]
                return None
            return value
        return None

    def set(self, key, value):
        self.cache[key] = (value, os.stat(self.index_file_path).st_mtime)

    def save(self):
        with open(self.index_file_path + '.cache', 'wb') as f:
            pickle.dump(self.cache, f)

    def load(self):
        if os.path.exists(self.index_file_path + '.cache'):
